export default function CVTimeline() {
  useEffect(() => {
    const mount = document.getElementById("lk-cv-timeline-mount");

    if (!mount) return;

    mount.innerHTML = cvTimelineHtml;

    window.dispatchEvent(new CustomEvent("lk-cv-timeline-ready"));

    return () => {
      mount.innerHTML = "";
    };
  }, []);

  return null;
}
